	       dcn10_read(mmio_base, DCSURF_PRIMARY_ADDRESS_HIGH),
	       dcn10_read(mmio_base, DCSURF_PRIMARY_ADDRESS),
	       dcn10_read(mmio_base, DCSURF_SURFACE_PITCH),
	       dcn10_read(mmio_base, BLANK_OFFSET_0),
	       dcn10_read(mmio_base, DST_DIMENSIONS),
	       dcn10_read(mmio_base, REF_FREQ_TO_PIX_FREQ));

	*pitch_bytes = pitch;
