 816	static void undo_DEGVIDCN10_253_wa(struct dc *dc)
 817	{
 818		struct dce_hwseq *hws = dc->hwseq;
 819		struct hubp *hubp = dc->res_pool->hubps[0];
 820	
 821		if (!hws->wa_state.DEGVIDCN10_253_applied)
