105	static uint32_t dcn10_read(void *mmio, uint32_t reg)
106	{
107		return read32((uint8_t *)mmio + DCN10_REG(reg));
108	}
109	
110	static void dcn10_write(void *mmio, uint32_t reg, uint32_t value)
111	{
112		write32((uint8_t *)mmio + DCN10_REG(reg), value);
113	}
114	
115	static void dcn10_update(void *mmio, uint32_t reg, uint32_t mask, uint32_t value)
116	{
117		uint32_t old = dcn10_read(mmio, reg);
118	
119		dcn10_write(mmio, reg, (old & ~mask) | (value & mask));
120	}
121	
122	void dcn10_disable_vga(void *mmio_base)
123	{
124		uint32_t vga_mode;
125	
126		vga_mode = read32((uint8_t *)mmio_base + DCN10_REG1(D1VGA_CONTROL)) |
127			read32((uint8_t *)mmio_base + DCN10_REG1(D2VGA_CONTROL)) |
128			read32((uint8_t *)mmio_base + DCN10_REG1(D3VGA_CONTROL)) |
129			read32((uint8_t *)mmio_base + DCN10_REG1(D4VGA_CONTROL));
130		if (!(vga_mode & 1))
131			return;
132	
133		write32((uint8_t *)mmio_base + DCN10_REG1(D1VGA_CONTROL), 0);
134		write32((uint8_t *)mmio_base + DCN10_REG1(D2VGA_CONTROL), 0);
135		write32((uint8_t *)mmio_base + DCN10_REG1(D3VGA_CONTROL), 0);
136		write32((uint8_t *)mmio_base + DCN10_REG1(D4VGA_CONTROL), 0);
137	
138		/* Linux dcn10_disable_vga(): make DCHUBP latch extended-mode timing. */
139		vga_mode = read32((uint8_t *)mmio_base + DCN10_REG1(VGA_TEST_CONTROL));
140		write32((uint8_t *)mmio_base + DCN10_REG1(VGA_TEST_CONTROL),
141			vga_mode | 0x101);
142		printk(BIOS_INFO, "ATOMBIOS: DCN1 VGA disabled; DCHUBP render update started\n");
143	}
144	
145	static int dcn10_power_on_domain(void *mmio, uint32_t config, uint32_t status)
146	{
147		unsigned int i;
148	
149		/* Linux dcn10_enable_power_gating_plane() plus hubp/dpp_pg_control(). */
150		dcn10_update(mmio, config, 0x101, 0x001);
151		for (i = 0; i < 1000; i++) {
152			if (!(dcn10_read(mmio, status) & 0xc0000000))
153				return 0;
154			udelay(1);
155		}
156		return -1;
157	}
158	
159	static void dcn10_fill_test_pattern(void *address, uint32_t pitch,
160					    uint16_t width, uint16_t height)
161	{
162		static const uint32_t colors[] = {
163			0xffff0000, 0xffffff00, 0xff00ff00,
164			0xff00ffff, 0xff0000ff, 0xffff00ff,
165		};
166		uint16_t x, y;
167	
168		for (y = 0; y < height; y++) {
169			uint32_t *row = (uint32_t *)((uint8_t *)address + y * pitch);
170	
171			for (x = 0; x < width; x++)
172				row[x] = colors[(x * 6U) / width];
173		}
174	}
175	
176	static uint32_t div_round_up_u64(uint64_t value, uint32_t divisor)
177	{
178		return (value + divisor - 1) / divisor;
179	}
180	
181	static void dcn10_program_timing(void *mmio, const struct dcn10_timing *timing)
182	{
183		uint32_t h_total = timing->h_active + timing->h_blank;
184		uint32_t v_total = timing->v_active + timing->v_blank;
185		uint32_t h_blank_start = h_total - timing->h_front_porch;
186		uint32_t h_blank_end = h_blank_start - timing->h_active;
187		uint32_t v_blank_start = v_total - timing->v_front_porch;
188		uint32_t v_blank_end = v_blank_start - timing->v_active;
189		uint32_t vstartup = timing->v_blank > 13 ? 13 : timing->v_blank - 1;
190		uint32_t vupdate_offset = (h_total + 3) / 4;
191		uint32_t vupdate_width;
192		uint32_t vready_offset;
193		uint32_t vready_dpp;
194		uint32_t vready_dcf;
195		uint32_t vcount_init = v_total - timing->v_front_porch;
196	
197		/* Linux DCN1 DML global-sync formulas; minimum deep-sleep DCFCLK is 8 MHz. */
198		vupdate_width = div_round_up_u64(14ULL * timing->pixel_clock_khz, 8000) +
199			div_round_up_u64(12ULL * timing->pixel_clock_khz,
200					 timing->disp_clock_khz);
201		vready_dpp = div_round_up_u64(150ULL * timing->pixel_clock_khz,
202					      timing->disp_clock_khz);
203		vready_dcf = div_round_up_u64(20ULL * timing->pixel_clock_khz, 8000) +
204			div_round_up_u64(10ULL * timing->pixel_clock_khz,
205					 timing->disp_clock_khz);
206		vready_offset = vready_dpp > vready_dcf ? vready_dpp : vready_dcf;
207	
208		/* Linux optc1_program_timing() for a progressive RGB eDP stream. */
209		dcn10_update(mmio, VTG_CONTROL, 0x80000000, 0);
210		dcn10_update(mmio, OTG_DOUBLE_BUFFER_CONTROL, 0x00010100, 0x00000100);
211		dcn10_write(mmio, OTG_H_TOTAL, h_total - 1);
212		dcn10_write(mmio, OTG_H_SYNC_A, (uint32_t)timing->h_sync_width << 16);
213		dcn10_write(mmio, OTG_H_BLANK_START_END,
214			    h_blank_start | (h_blank_end << 16));
215		dcn10_update(mmio, OTG_H_SYNC_A_CNTL, 1,
216			     timing->hsync_positive ? 0 : 1);
217		dcn10_write(mmio, OTG_H_TIMING_CNTL, 0);
218	
219		dcn10_write(mmio, OTG_V_TOTAL, v_total - 1);
220		dcn10_write(mmio, OTG_V_TOTAL_MIN, v_total - 1);
221		dcn10_write(mmio, OTG_V_TOTAL_MAX, v_total - 1);
222		dcn10_write(mmio, OTG_V_SYNC_A, (uint32_t)timing->v_sync_width << 16);
223		dcn10_write(mmio, OTG_V_BLANK_START_END,
224			    v_blank_start | (v_blank_end << 16));
225		dcn10_update(mmio, OTG_V_SYNC_A_CNTL, 1,
226			     timing->vsync_positive ? 0 : 1);
227		dcn10_write(mmio, OTG_INTERLACE_CONTROL, 0);
228	
229		dcn10_write(mmio, OTG_VSTARTUP_PARAM, vstartup);
230		dcn10_write(mmio, OTG_VUPDATE_PARAM,
231			    vupdate_offset | (vupdate_width << 16));
232		dcn10_write(mmio, OTG_VREADY_PARAM, vready_offset);
233		dcn10_update(mmio, OTG_CONTROL, 0x7000, 1U << 12);
234		dcn10_update(mmio, VTG_CONTROL, 0x3fff8000, vcount_init << 15);
235	}
236	
237	static void dcn10_program_dlg_ttu(void *mmio, const struct dcn10_timing *timing,
238					  uint32_t pitch_pixels)
239	{
240		uint32_t h_total = timing->h_active + timing->h_blank;
241		uint32_t v_total = timing->v_active + timing->v_blank;
242		uint32_t h_blank_end = h_total - timing->h_front_porch - timing->h_active;
243		uint32_t v_blank_start = v_total - timing->v_front_porch;
244		uint32_t v_blank_end = v_blank_start - timing->v_active;
245		uint64_t ratio;
246		uint32_t refcyc_per_htotal;
247		uint32_t refcyc_h_blank_end;
248		uint32_t pixel_delay;
249		uint32_t refcyc_x_after_scaler;
250		uint32_t line_delivery;
251		uint32_t requests_per_line;
252		uint32_t request_delivery;
253		uint32_t qos_high;
254		uint32_t min_ttu;
255	
256		/* Integer subset of Linux dml1_rq_dlg_get_dlg_params(), no VM or DCC. */
257		ratio = ((uint64_t)timing->ref_clock_khz << 19) /
258			timing->pixel_clock_khz;
259		refcyc_per_htotal = (ratio * h_total * 256) >> 19;
260		refcyc_h_blank_end = (ratio * h_blank_end) >> 19;
261		pixel_delay = (132ULL * timing->pixel_clock_khz) /
262			timing->disp_clock_khz;
263		refcyc_x_after_scaler = (ratio * pixel_delay) >> 19;
264		line_delivery = ((uint64_t)timing->ref_clock_khz * timing->h_active) /
265			timing->pixel_clock_khz;
266		requests_per_line = (pitch_pixels * 4 + 255) / 256;
267		request_delivery = ((uint64_t)line_delivery << 10) / requests_per_line;
268		qos_high = ((uint64_t)4 * h_total * timing->ref_clock_khz) /
269			timing->pixel_clock_khz;
270		min_ttu = 4 * timing->ref_clock_khz / 1000 +
271			24 * timing->ref_clock_khz / timing->disp_clock_khz;
272	
273		dcn10_write(mmio, BLANK_OFFSET_0,
274			    refcyc_h_blank_end | (v_blank_end << 16));
275		dcn10_write(mmio, BLANK_OFFSET_1, v_blank_start * 4);
276		dcn10_write(mmio, DST_DIMENSIONS, refcyc_per_htotal);
277		dcn10_write(mmio, DST_AFTER_SCALER, refcyc_x_after_scaler);
278		dcn10_write(mmio, REF_FREQ_TO_PIX_FREQ, ratio);
279		dcn10_write(mmio, PREFETCH_SETTINS, (16U << 24) | (1U << 19));
280		dcn10_write(mmio, VBLANK_PARAMETERS_0, 0);
281		dcn10_write(mmio, PER_LINE_DELIVERY_PRE, line_delivery);
282		dcn10_write(mmio, PER_LINE_DELIVERY, line_delivery);
283		dcn10_write(mmio, DCN_TTU_QOS_WM, qos_high << 16);
284		dcn10_write(mmio, DCN_SURF0_TTU_CNTL0,
285			    request_delivery | (8U << 24));
286		dcn10_write(mmio, DCN_SURF0_TTU_CNTL1, request_delivery);
287		dcn10_write(mmio, DCN_GLOBAL_TTU_CNTL, min_ttu | (14U << 28));
288	}
289	
290	int dcn10_program_scanout(void *mmio_base, uint64_t gpu_address,
291				  void *cpu_address, size_t aperture_size,
292				  const struct dcn10_timing *timing,
293				  uint32_t *pitch_bytes)
294	{
295		uint16_t width;
296		uint16_t height;
297		uint32_t pitch_pixels;
298		uint32_t pitch;
299		uint32_t dimensions;
300		uint32_t hubp_cntl;
301	
302		if (!mmio_base || !cpu_address || !gpu_address || !timing ||
303		    !timing->pixel_clock_khz || !timing->ref_clock_khz ||
304		    !timing->disp_clock_khz || timing->v_blank < 2)
305			return -1;
306		width = timing->h_active;
307		height = timing->v_active;
308		pitch_pixels = (width + 63U) & ~63U;
309		pitch = pitch_pixels * 4U;
310		dimensions = ((uint32_t)height << 16) | width;
311		if (aperture_size < (size_t)pitch * height)
312			return -1;
313		if (dcn10_power_on_domain(mmio_base, DOMAIN0_PG_CONFIG, DOMAIN0_PG_STATUS) ||
314		    dcn10_power_on_domain(mmio_base, DOMAIN1_PG_CONFIG, DOMAIN1_PG_STATUS)) {
315			printk(BIOS_ERR, "ATOMBIOS: DCN1 HUBP/DPP power-on failed\n");
316			return -1;
317		}
318	
319		/* Linux hubp1_set_blank(): stop requests while changing the plane. */
320		hubp_cntl = dcn10_read(mmio_base, DCHUBP_CNTL);
321		hubp_cntl &= ~HUBP_VTG_SEL_MASK;
322		hubp_cntl |= HUBP_BLANK_EN | HUBP_TTU_DISABLE;
323		dcn10_write(mmio_base, DCHUBP_CNTL, hubp_cntl);
324	
325		/* Linux hubp1_clk_cntl(), dpp1_dppclk_control(), opp_pipe_clock_control(). */
326		dcn10_update(mmio_base, HUBP_CLK_CNTL, HUBP_CLOCK_ENABLE, HUBP_CLOCK_ENABLE);
327		dcn10_update(mmio_base, DPP_CONTROL, DPP_CLOCK_ENABLE, DPP_CLOCK_ENABLE);
328		dcn10_update(mmio_base, OPP_PIPE_CONTROL,
329			     OPP_PIPE_CLOCK_ENABLE, OPP_PIPE_CLOCK_ENABLE);
330	
331		/* Linux dml1_extract_rq_regs() values for one linear 32-bpp RGB plane. */
332		dcn10_write(mmio_base, DCN_EXPANSION_MODE, 0x56);
333		dcn10_write(mmio_base, DCHUBP_REQ_SIZE_CONFIG, 0x055d1b70);
334		dcn10_program_dlg_ttu(mmio_base, timing, pitch_pixels);
335	
336		/* Linear, non-DCC ARGB8888 surface, matching hubp1_program_surface_config(). */
337		dcn10_update(mmio_base, DCSURF_SURFACE_CONTROL, 0x3f, 0);
338		dcn10_write(mmio_base, DCSURF_TILING_CONFIG, 0);
339		dcn10_update(mmio_base, DCSURF_SURFACE_CONFIG, 0x0000077f, 8);
340		dcn10_write(mmio_base, DCSURF_SURFACE_PITCH, pitch_pixels - 1);
341		dcn10_write(mmio_base, DCSURF_PRI_VIEWPORT_START, 0);
342		dcn10_write(mmio_base, DCSURF_PRI_VIEWPORT_DIMENSION, dimensions);
343		dcn10_update(mmio_base, DCSURF_FLIP_CONTROL, 0x2, 0);
344	
345		/* Linux hubp1_program_pixel_format() crossbar for ARGB. */
346		dcn10_update(mmio_base, HUBPRET_CONTROL, 0x00f00fff, 0x00e00000);
347	
348		/* Linux dpp1_cnv_setup() and 1:1 dpp1_dscl_set_scaler_manual_scale(). */
349		dcn10_write(mmio_base, CNVC_SURFACE_PIXEL_FORMAT, 8);
350		dcn10_write(mmio_base, CNVC_FORMAT_CONTROL, 0x00000100);
351		dcn10_write(mmio_base, DSCL_CONTROL, 0);
352		dcn10_write(mmio_base, DSCL_RECOUT_START, 0);
353		dcn10_write(mmio_base, DSCL_RECOUT_SIZE, dimensions);
354		dcn10_write(mmio_base, DSCL_MPC_SIZE, dimensions);
355		dcn10_update(mmio_base, DSCL_SCL_MODE, 0x7, 6);
356	
357		/* Linux mpc1_insert_plane(): DPP0 -> MPCC0 -> OPP0. */
358		dcn10_update(mmio_base, MPCC_BOT_SEL, 0xf, 0xf);
359		dcn10_update(mmio_base, MPCC_CONTROL, 0x3, 2);
360		dcn10_update(mmio_base, MPCC_TOP_SEL, 0xf, 0);
361		dcn10_update(mmio_base, MPCC_OPP_ID, 0xf, 0);
362		dcn10_update(mmio_base, MPCC_UPDATE_LOCK_SEL, 0xf, 0);
363		dcn10_update(mmio_base, MPC_OUT_MUX, 0xf, 0);
364	
365		/* Linux optc1_enable_optc_clock(), optc1_enable_crtc(), and unblank. */
366		dcn10_program_timing(mmio_base, timing);
367		dcn10_update(mmio_base, OPTC_INPUT_CLOCK_CONTROL, 0x3, 0x3);
368		dcn10_update(mmio_base, OTG_CLOCK_CONTROL, 0x3, 0x3);
369		mdelay(1);
370		dcn10_update(mmio_base, OPTC_DATA_SOURCE_SELECT, 0x700, 0);
371		dcn10_update(mmio_base, VTG_CONTROL, 0x80000000, 0x80000000);
372		dcn10_update(mmio_base, OTG_CONTROL, 0x301, 0x301);
373		dcn10_update(mmio_base, OTG_BLANK_CONTROL, 0x00010100, 0);
374		printk(BIOS_INFO,
375		       "ATOMBIOS: DCN1 OTG ctrl=0x%08x blank=0x%08x clock=0x%08x "
376		       "input=0x%08x vtg=0x%08x htotal=0x%08x vtotal=0x%08x "
377		       "vstartup=0x%08x vupdate=0x%08x vready=0x%08x\n",
378		       dcn10_read(mmio_base, OTG_CONTROL),
379		       dcn10_read(mmio_base, OTG_BLANK_CONTROL),
380		       dcn10_read(mmio_base, OTG_CLOCK_CONTROL),
381		       dcn10_read(mmio_base, OPTC_INPUT_CLOCK_CONTROL),
382		       dcn10_read(mmio_base, VTG_CONTROL),
383		       dcn10_read(mmio_base, OTG_H_TOTAL),
384		       dcn10_read(mmio_base, OTG_V_TOTAL),
385		       dcn10_read(mmio_base, OTG_VSTARTUP_PARAM),
386		       dcn10_read(mmio_base, OTG_VUPDATE_PARAM),
387		       dcn10_read(mmio_base, OTG_VREADY_PARAM));
388	
389		dcn10_fill_test_pattern(cpu_address, pitch, width, height);
390	
391		/* Linux hubp1_program_surface_flip_and_addr(): high first, low latches. */
392		dcn10_write(mmio_base, DCSURF_PRIMARY_ADDRESS_HIGH, gpu_address >> 32);
393		dcn10_write(mmio_base, DCSURF_PRIMARY_ADDRESS, gpu_address);
394	
395		/* Linux hubp1_set_blank(false). */
396		hubp_cntl = dcn10_read(mmio_base, DCHUBP_CNTL);
397		hubp_cntl &= ~(HUBP_BLANK_EN | HUBP_DISABLE |
398			       HUBP_TTU_DISABLE | HUBP_VTG_SEL_MASK);
399		dcn10_write(mmio_base, DCHUBP_CNTL, hubp_cntl);
400		mdelay(20);
401		printk(BIOS_INFO,
402		       "ATOMBIOS: DCN1 HUBP cntl=0x%08x earliest=0x%08x%08x "
403		       "address=0x%08x%08x pitch=0x%08x dlg=0x%08x/0x%08x/0x%08x\n",
404		       dcn10_read(mmio_base, DCHUBP_CNTL),
405		       dcn10_read(mmio_base, DCSURF_EARLIEST_INUSE_HIGH),
406		       dcn10_read(mmio_base, DCSURF_EARLIEST_INUSE),
407		       dcn10_read(mmio_base, DCSURF_PRIMARY_ADDRESS_HIGH),
408		       dcn10_read(mmio_base, DCSURF_PRIMARY_ADDRESS),
409		       dcn10_read(mmio_base, DCSURF_SURFACE_PITCH),
410		       dcn10_read(mmio_base, BLANK_OFFSET_0),
411		       dcn10_read(mmio_base, DST_DIMENSIONS),
412		       dcn10_read(mmio_base, REF_FREQ_TO_PIX_FREQ));
413	
414		*pitch_bytes = pitch;
415		printk(BIOS_INFO,
416		       "ATOMBIOS: DCN1 scanout %ux%u pitch=%u GPU=0x%016llx CPU=%p\n",
417		       width, height, pitch, (unsigned long long)gpu_address, cpu_address);
418		return 0;
419	}

