 11	/* Raven/Picasso DCN segments, from Linux vega10_ip_offset.h. */
 12	#define DCN10_SEG1_BASE	0x00c0
 13	#define DCN10_SEG2_BASE	0x34c0
 14	#define DCN10_REG1(reg)	((DCN10_SEG1_BASE + (reg)) * 4)
 15	#define DCN10_REG(reg)	((DCN10_SEG2_BASE + (reg)) * 4)
 16	
 17	#define D1VGA_CONTROL			0x000c
 18	#define D2VGA_CONTROL			0x000e
 19	#define VGA_TEST_CONTROL		0x0015
 20	#define D3VGA_CONTROL			0x0038
 21	#define D4VGA_CONTROL			0x0039
 22	
 23	#define DOMAIN0_PG_CONFIG		0x008a
 24	#define DOMAIN0_PG_STATUS		0x008b
 25	#define DOMAIN1_PG_CONFIG		0x008c
 26	#define DOMAIN1_PG_STATUS		0x008d
 27	
 28	#define DCSURF_SURFACE_CONFIG		0x0559
 29	#define DCSURF_TILING_CONFIG		0x055b
 30	#define DCSURF_PRI_VIEWPORT_START	0x055c
 31	#define DCSURF_PRI_VIEWPORT_DIMENSION	0x055d
 32	#define DCHUBP_REQ_SIZE_CONFIG		0x0564
 33	#define DCHUBP_CNTL			0x0566
 34	#define HUBP_CLK_CNTL			0x0567
 35	#define DCSURF_SURFACE_PITCH		0x057b
 36	#define DCSURF_PRIMARY_ADDRESS		0x057d
 37	#define DCSURF_PRIMARY_ADDRESS_HIGH	0x057e
 38	#define DCSURF_SURFACE_CONTROL		0x058d
 39	#define DCSURF_FLIP_CONTROL		0x058e
 40	#define DCSURF_EARLIEST_INUSE		0x0597
 41	#define DCSURF_EARLIEST_INUSE_HIGH	0x0598
 42	#define DCN_EXPANSION_MODE		0x059b
 43	#define DCN_TTU_QOS_WM			0x059c
 44	#define DCN_GLOBAL_TTU_CNTL		0x059d
 45	#define DCN_SURF0_TTU_CNTL0		0x059e
 46	#define DCN_SURF0_TTU_CNTL1		0x059f
 47	#define BLANK_OFFSET_0			0x05b6
 48	#define BLANK_OFFSET_1			0x05b7
 49	#define DST_DIMENSIONS			0x05b8
 50	#define DST_AFTER_SCALER		0x05b9
 51	#define PREFETCH_SETTINS		0x05ba
 52	#define VBLANK_PARAMETERS_0		0x05bc
 53	#define PER_LINE_DELIVERY_PRE		0x05c9
 54	#define PER_LINE_DELIVERY		0x05ca
 55	#define REF_FREQ_TO_PIX_FREQ		0x05cc
 56	#define HUBPRET_CONTROL			0x05e0
 57	#define VTG_CONTROL			0x0528
 58	
 59	#define DPP_CONTROL			0x0c3d
 60	#define CNVC_SURFACE_PIXEL_FORMAT	0x0c47
 61	#define CNVC_FORMAT_CONTROL		0x0c48
 62	#define DSCL_SCL_MODE			0x0c64
 63	#define DSCL_CONTROL			0x0c66
 64	#define DSCL_RECOUT_START		0x0c7a
 65	#define DSCL_RECOUT_SIZE		0x0c7b
 66	#define DSCL_MPC_SIZE			0x0c7c
 67	
 68	#define MPCC_TOP_SEL			0x1630
 69	#define MPCC_BOT_SEL			0x1631
 70	#define MPCC_OPP_ID			0x1632
 71	#define MPCC_CONTROL			0x1633
 72	#define MPCC_UPDATE_LOCK_SEL		0x1635
 73	#define MPC_OUT_MUX			0x172f
 74	#define OPP_PIPE_CONTROL		0x188c
 75	#define OPTC_DATA_SOURCE_SELECT		0x1acb
 76	#define OPTC_INPUT_CLOCK_CONTROL	0x1acd
 77	#define OTG_H_TOTAL			0x1b2a
 78	#define OTG_H_BLANK_START_END		0x1b2b
 79	#define OTG_H_SYNC_A			0x1b2c
 80	#define OTG_H_SYNC_A_CNTL		0x1b2d
 81	#define OTG_H_TIMING_CNTL		0x1b2e
 82	#define OTG_V_TOTAL			0x1b2f
 83	#define OTG_V_TOTAL_MIN			0x1b30
 84	#define OTG_V_TOTAL_MAX			0x1b31
 85	#define OTG_V_BLANK_START_END		0x1b36
 86	#define OTG_V_SYNC_A			0x1b37
 87	#define OTG_V_SYNC_A_CNTL		0x1b38
 88	#define OTG_CONTROL			0x1b41
 89	#define OTG_BLANK_CONTROL		0x1b42
 90	#define OTG_INTERLACE_CONTROL		0x1b44
 91	#define OTG_DOUBLE_BUFFER_CONTROL	0x1b5b
 92	#define OTG_CLOCK_CONTROL		0x1b88
 93	#define OTG_VSTARTUP_PARAM		0x1b89
 94	#define OTG_VUPDATE_PARAM		0x1b8a
 95	#define OTG_VREADY_PARAM		0x1b8b
 96	
 97	#define HUBP_BLANK_EN			(1U << 0)
 98	#define HUBP_DISABLE			(1U << 2)
 99	#define HUBP_VTG_SEL_MASK		(0xfU << 4)
100	#define HUBP_TTU_DISABLE		(1U << 12)
101	#define HUBP_CLOCK_ENABLE		(1U << 0)
102	#define DPP_CLOCK_ENABLE		(1U << 4)
103	#define OPP_PIPE_CLOCK_ENABLE		(1U << 0)
104	
105	static uint32_t dcn10_read(void *mmio, uint32_t reg)
106	{
107		return read32((uint8_t *)mmio + DCN10_REG(reg));
108	}
109	
110	static void dcn10_write(void *mmio, uint32_t reg, uint32_t value)
111	{
112		write32((uint8_t *)mmio + DCN10_REG(reg), value);
113	}
114	
115	static void dcn10_update(void *mmio, uint32_t reg, uint32_t mask, uint32_t value)
116	{
117		uint32_t old = dcn10_read(mmio, reg);
118	
119		dcn10_write(mmio, reg, (old & ~mask) | (value & mask));
120	}
121	
122	void dcn10_disable_vga(void *mmio_base)
123	{
124		uint32_t vga_mode;
125	
126		vga_mode = read32((uint8_t *)mmio_base + DCN10_REG1(D1VGA_CONTROL)) |
127			read32((uint8_t *)mmio_base + DCN10_REG1(D2VGA_CONTROL)) |
128			read32((uint8_t *)mmio_base + DCN10_REG1(D3VGA_CONTROL)) |
129			read32((uint8_t *)mmio_base + DCN10_REG1(D4VGA_CONTROL));
130		if (!(vga_mode & 1))
131			return;
132	
133		write32((uint8_t *)mmio_base + DCN10_REG1(D1VGA_CONTROL), 0);
134		write32((uint8_t *)mmio_base + DCN10_REG1(D2VGA_CONTROL), 0);
135		write32((uint8_t *)mmio_base + DCN10_REG1(D3VGA_CONTROL), 0);
136		write32((uint8_t *)mmio_base + DCN10_REG1(D4VGA_CONTROL), 0);
137	
138		/* Linux dcn10_disable_vga(): make DCHUBP latch extended-mode timing. */
139		vga_mode = read32((uint8_t *)mmio_base + DCN10_REG1(VGA_TEST_CONTROL));
140		write32((uint8_t *)mmio_base + DCN10_REG1(VGA_TEST_CONTROL),
141			vga_mode | 0x101);
142		printk(BIOS_INFO, "ATOMBIOS: DCN1 VGA disabled; DCHUBP render update started\n");
143	}
144	
145	static int dcn10_power_on_domain(void *mmio, uint32_t config, uint32_t status)
146	{
147		unsigned int i;
148	
149		/* Linux dcn10_enable_power_gating_plane() plus hubp/dpp_pg_control(). */
150		dcn10_update(mmio, config, 0x101, 0x001);
151		for (i = 0; i < 1000; i++) {
152			if (!(dcn10_read(mmio, status) & 0xc0000000))
153				return 0;
154			udelay(1);
155		}
156		return -1;
157	}
