4577	static int atomfirmware_enable_edp_link(struct atom_context *ctx,
4578						const struct atom_v2_display_path *v2_path,
4579						const struct edid_mode *mode)
4580	{
4581		struct atombios_display_path path = {
4582			.connector_type = 2,
4583			.encoder_obj_id = atombios_object_id(v2_path->encoder_objid),
4584			.i2c_line = v2_path->i2c_id,
4585			.i2c_valid = v2_path->i2c_valid,
4586			.hpd_id = v2_path->hpd_valid ? v2_path->hpd_pin : v2_path->phy_id,
4587			.dig_encoder = v2_path->dig_encoder,
4588			.phy_id = v2_path->phy_id,
4589			.encoder_mode = ATOM_ENCODER_MODE_DP,
4590			.pll_id = ATOM_COMBOPHY_PLL0 + v2_path->phy_id,
4591			.tx_refclk = ATOM_COMBOPHY_PLL0 + v2_path->phy_id,
4592			.connector_obj_id = CONNECTOR_OBJECT_ID_eDP,
4593			.device_tag = v2_path->device_tag,
4594		};
4595		uint16_t pixel_clock_10khz = mode->pixel_clock / 10;
4596	
4597		if (atombios_dp_prepare_link(ctx, &path, mode->pixel_clock) ||
4598		    atombios_transmitter_control(ctx, &path, pixel_clock_10khz,
4599						 ATOM_TRANSMITTER_ACTION_INIT, 0, 0) ||
4600		    atombios_dig_encoder_setup(ctx, &path, pixel_clock_10khz,
4601					       ATOM_ENCODER_CMD_STREAM_SETUP,
4602					       PANEL_8BIT_PER_COLOR) ||
4603		    atombios_dig_encoder_setup(ctx, &path, pixel_clock_10khz,
4604					       ATOM_ENCODER_CMD_SETUP_PANEL_MODE,
4605					       PANEL_8BIT_PER_COLOR) ||
4606		    atombios_select_crtc_source(ctx, &path, ATOM_CRTC1) ||
4607		    atombios_set_pixel_clock(ctx, &path, pixel_clock_10khz, ATOM_CRTC1) ||
4608		    atombios_set_crtc_dtd_timing(ctx, mode, ATOM_CRTC1) ||
4609		    atombios_enable_crtc(ctx, ATOM_CRTC1, 1) ||
4610		    atombios_transmitter_control(ctx, &path, pixel_clock_10khz,
4611						 ATOM_TRANSMITTER_ACTION_ENABLE, 0, 0) ||
4612		    atombios_dp_link_train(ctx, &path, pixel_clock_10khz,
4613					   path.i2c_line, path.hpd_id) ||
4614		    atombios_blank_crtc(ctx, ATOM_CRTC1, 0) ||
4615		    atombios_transmitter_control(ctx, &path, pixel_clock_10khz,
4616						 ATOM_TRANSMITTER_ACTION_LCD_BLON, 0, 0))
4617			return -1;
