4843							.v_sync_width = edid.mode.vspw,
4844							.pixel_clock_khz = edid.mode.pixel_clock,
4845							.ref_clock_khz = v2_dce.dce_refclk_10khz * 10,
4846							.disp_clock_khz = v2_dce.boot_dispclk_10khz * 10,
4847							.hsync_positive = edid.mode.phsync,
4848							.vsync_positive = edid.mode.pvsync,
4849						};
4850						uint32_t pitch;
4851	
4852						if (dcn10_program_scanout(mmio_base, v2_fw.mc_base,
4853								   (void *)(uintptr_t)fb_bar, fb_size,
